{
  "$schema": "../node_modules/@tauri-apps/cli/config.schema.json",
  "productName": "Raycast Clone",
  "version": "0.1.0",
  "identifier": "com.antoniopresto.raycastclone",
  "build": {
    "frontendDist": "../dist",
    "devUrl": "http://localhost:5173",
    "beforeDevCommand": "bun run dev",
    "beforeBuildCommand": "bun run build"
  },
  "app": {
    "windows": [
      {
        "label": "main",
        "title": "Raycast",
        "width": 750,
        "height": 500,
        "center": true,
        "decorations": false,
        "transparent": true,
        "resizable": false,
        "maximizable": false,
        "fullscreen": false,
        "alwaysOnTop": true,
        "shadow": true
      }
    ],
    "security": {
      "csp": null
    }
  },
  "bundle": {
    "active": true,
    "targets": "all",
    "icon": [
      "icons/32x32.png",
      "icons/128x128.png",
      "icons/128x128@2x.png",
      "icons/icon.icns",
      "icons/icon.ico"
    ]
  }
}

